import re

def count_politician_mentions(articles, politician_names):
    # Convert politician names to lowercase for case-insensitive matching
    lowercase_names = {name.lower() for name in politician_names}

    # Initialize a dictionary to store the counts
    counts = {name: 0 for name in politician_names}

    # Process each article
    for article in articles:
        # Remove punctuation and convert to lowercase
        cleaned_article = re.sub(r'[^\w\s]', '', article).lower()

        # Split the article into words
        words = cleaned_article.split()

        # Count occurrences of each politician's name
        for word in words:
            if word in lowercase_names:
                # Find the corresponding original name
                for name in politician_names:
                    if word == name.lower():
                        counts[name] += 1
                        break
    return counts
